def _require_pillow():
    try:
        from PIL import Image, ImageFile
    except ImportError as error:
        raise WebpCodecError(
            "WebP support requires Pillow. Install pillow in the server environment."
        ) from error
    ImageFile.LOAD_TRUNCATED_IMAGES = True
    return Image

