def decode_webp(data: bytes) -> Raster:
    if len(data) < 12 or data[0:4] != b"RIFF" or data[8:12] != b"WEBP":
        raise WebpCodecError("Not a WebP image.")
    Image = _require_pillow()
    try:
        with Image.open(io.BytesIO(data)) as image:
            image.load()
            if image.format != "WEBP":
                raise WebpCodecError("Payload is not a valid WebP image.")
            return _raster_from_image(image)
    except OSError as error:
        raise WebpCodecError(f"Could not decode WebP image: {error}") from error

