def encode_webp(raster: Raster, quality: int = 80, lossless: bool = False) -> bytes:
    Image = _require_pillow()
    quality = max(1, min(100, int(quality)))
    buffer = io.BytesIO()
    if raster.channels == 4:
        image = Image.frombytes("RGBA", (raster.width, raster.height), bytes(raster.data))
    else:
        image = Image.frombytes("RGB", (raster.width, raster.height), bytes(raster.to_rgb().data))
    try:
        image.save(
            buffer,
            format="WEBP",
            quality=quality,
            lossless=lossless,
            method=4,
        )
    except OSError as error:
        raise WebpCodecError(f"Could not encode WebP image: {error}") from error
    return buffer.getvalue()
